import React, { useEffect, useState } from 'react'
import { Link, useParams } from 'react-router-dom'
import axios from "axios"


export default function ItemsPage() {
    const {action} = useParams()
    const [category,setCategory] = useState("upper");
    const [items,setItems] = useState({
        icategory:"upper",
        iname:"",
        imrp:"",
        isize:"",
        imaterial:"",
        icondition:"",
        prop1:"",
        prop2:"",
        prop3:"",
        prop4:"",
        prop5:""
    })

    const [addedPhotos ,setAddedPhotos] = useState([])

    const handleChange=(e)=>{
        setItems({...items ,[e.target.name]:e.target.value})
    }
    const handleSubmit =(e)=>{
        e.preventDefault();
        console.log(items)
    }
    const handleCategory =(e)=>{
        setCategory(e.target.value)
        setItems({...items, icategory: e.target.value});
    }

    
    const uploadPhoto= async(e)=>{
      const files = e.target.files;
      const data = new FormData();
      for(let i=0;i<files.length ;i++)
      {
          data.append('photos',files[i])
      }
      try {
          const res  =await axios.post('/uploads',data,{
            headers:{'Content-type':'multipart/form-data'}
          })
          const {value} = res.data
          console.log(value)
      } catch (error) {
        console.log(error)
      }
    }

  return (
    <div>
    {
        action !== 'new' && 
        <Link className="flex justify-center w-full mt-8" to={'/account/items/new'}>Add New Item</Link>   
    }
    {
        action === "new" && (
            <div> 
               <h1 className="flex justify-center w-full mt-8" >FORM</h1>
               <div>
               <label htmlFor="icategory">Item Category : </label>
                    <select name="icategory" id="icategory" onChange={handleCategory}>
                        <option value="upper">Upper Garment</option>
                        <option value="lower">Lower Garment</option>
                    </select><br />
               </div>
               <div>
                <form >
                    <label htmlFor="iname">Item Name : </label>
                    <input type="text" name='iname' id='iname' onChange={handleChange} value={items.iname}/><br />
                    <label htmlFor="imrp">MRP : </label>
                    <input type="text" name='imrp' id='imrp' onChange={handleChange} value={items.imrp}/><br />
                    <label htmlFor="isize">Item Size : </label>
                    <select name="isize" id="isize" onChange={handleChange} value={items.isize}>
                        <option value="null">Select Size</option>
                        <option value="large">Large</option>
                        <option value="medium">Medium</option>
                        <option value="small">Small</option>
                    </select><br />
                    <label htmlFor="imaterial">Item Material : </label>
                    <select name="imaterial" id="imaterial" onChange={handleChange} value={items.imaterial}>
                       <option value="null">Select Material</option>
                        <option value="cotton">Cotton</option>
                        <option value="silk">Silk</option>
                        <option value="nylon">Nylon</option>
                        <option value="other">Other</option>
                    </select><br />
                    <label htmlFor="icondition">Item Condition : </label>
                    <select name="icondition" id="icondition" onChange={handleChange} value={items.icondition}>
                       <option value="null">Select Condition</option>
                        <option value="brandnew">Brand New</option>
                        <option value="yearold">A Year Old</option>
                        <option value="colorissue">Color Issues </option>
                    </select><br />
                    <h2>Photos</h2>
                    <div className='mt-2 grid grid-cols-3 gap-2 md:grid-cols-4 lg:grid-cols-6'>
                    { addedPhotos.length>0 && addedPhotos.map(link=>(
                            <div> 
                                <img src={''} />
                            </div>
                        ))}
                    <label className=' cursor-pointer border bg-transparent rounded-2xl p-8 text-2xl text-gray-500'>+
                    <input type="file" multiple name="ifile" id="ifile" className='hidden' onChange={uploadPhoto} />
                    </label>
                    </div>
                    <h3>Measurements</h3><br />
                    <label htmlFor="prop1">{category==='upper' ? "Shoulder : " : "Waist  : "} </label>
                    <input type="text" name='prop1' id='prop1' onChange={handleChange} value={items.prop1}/><br />
                    <label htmlFor="prop2">{category==='upper' ? "Sleeve Length : " : "Hip  : "}</label>
                    <input type="text" name='prop2' id='prop2' onChange={handleChange} value={items.prop2}/><br />
                    <label htmlFor="prop3">{category==='upper' ? "Chest : " : "Rise  : "} </label>
                    <input type="text" name='prop3' id='prop3' onChange={handleChange} value={items.prop3}/><br />
                    <label htmlFor="prop4">{category==='upper' ? "Waist : " : "Length  : "}</label>
                    <input type="text" name='prop4' id='prop4' onChange={handleChange} value={items.prop4}/><br />
                    <label htmlFor="prop5">{category==='upper' ? "Length : " : "Thigh Round  : "} </label>
                    <input type="text" name='prop5' id='prop5' onChange={handleChange} value={items.prop5}/><br />
                    <br />
                    <input type="submit" name="submit" id="submit" onClick={handleSubmit} />
                </form>
               </div>
            </div>
        )
    }
        </div>
  )
}
